import{_ as e,c as t,o as a,a as r}from"./app.606ab571.js";const m=JSON.parse('{"title":"Ticketing System","description":"","frontmatter":{},"headers":[{"level":2,"title":"Architecture Approach","slug":"architecture-approach","link":"#architecture-approach","children":[]},{"level":2,"title":"Key Patterns","slug":"key-patterns","link":"#key-patterns","children":[]},{"level":2,"title":"Stack","slug":"stack","link":"#stack","children":[]},{"level":2,"title":"Docs","slug":"docs","link":"#docs","children":[]}],"relativePath":"index.md"}'),n={name:"index.md"},i=r('<h1 id="ticketing-system" tabindex="-1">Ticketing System <a class="header-anchor" href="#ticketing-system" aria-hidden="true">#</a></h1><p>A backend system for high-concurrency ticket booking, built as a pet project to explore distributed systems patterns in a realistic domain.</p><p>The system handles the full reservation lifecycle \u2014 from seat selection through payment confirmation to inventory update \u2014 while staying correct under concurrent load. The core challenge is that multiple users can attempt to book the same seat simultaneously, and the system must guarantee that only one succeeds without sacrificing performance.</p><h2 id="architecture-approach" tabindex="-1">Architecture Approach <a class="header-anchor" href="#architecture-approach" aria-hidden="true">#</a></h2><p>The system is built around <strong>Domain-Driven Design</strong> principles. Business logic lives in the domain layer \u2014 aggregates like <code>Reservation</code>, <code>Payment</code>, and <code>Screening</code> own their state transitions and enforce their own invariants. Nothing outside the domain can put an aggregate into an invalid state.</p><p>The application layer orchestrates use cases through <strong>CQRS</strong> \u2014 commands mutate state, queries read it, and they are handled independently via MediatR. Infrastructure concerns like persistence, caching, and messaging are kept behind interfaces defined by the application layer.</p><h2 id="key-patterns" tabindex="-1">Key Patterns <a class="header-anchor" href="#key-patterns" aria-hidden="true">#</a></h2><p><strong>Outbox Pattern</strong> \u2014 domain events are persisted to the database in the same transaction as the state change, then dispatched asynchronously by a background worker. This guarantees at-least-once delivery without coupling the HTTP response to event processing.</p><p><strong>Two-layer concurrency</strong> \u2014 seat reservation uses Redis distributed locks to fail fast under contention, backed by EF Core optimistic concurrency as the correctness guarantee at the database level. The two layers are complementary: Redis is a performance optimization, the database is the source of truth.</p><p><strong>Event-driven flow</strong> \u2014 the reservation, payment, and seat-sold chain is driven entirely by domain events. No handler calls another handler directly \u2014 each step completes, raises an event, and the next step is triggered asynchronously through the outbox.</p><h2 id="stack" tabindex="-1">Stack <a class="header-anchor" href="#stack" aria-hidden="true">#</a></h2><ul><li><strong><a href="http://ASP.NET" target="_blank" rel="noreferrer">ASP.NET</a> Core</strong> \u2014 HTTP API</li><li><strong>PostgreSQL</strong> \u2014 primary database</li><li><strong>Redis</strong> \u2014 distributed seat locking</li><li><strong>EF Core</strong> \u2014 ORM with optimistic concurrency</li><li><strong>MediatR</strong> \u2014 CQRS command/query dispatching</li><li><strong>Serilog</strong> \u2014 structured logging with correlation ID tracing</li><li><strong>xUnit</strong> \u2014 unit and integration tests against a real database</li></ul><h2 id="docs" tabindex="-1">Docs <a class="header-anchor" href="#docs" aria-hidden="true">#</a></h2><ul><li><a href="./architecture.html">Architecture</a></li><li><a href="./cqrs.html">CQRS</a></li><li><a href="./concurrency.html">Concurrency</a></li><li><a href="./domain-model.html">Domain Model</a></li><li><a href="./messaging.html">Messaging</a></li><li><a href="./outbox-pattern.html">Outbox Pattern</a></li><li><a href="./redis-locking.html">Redis Locking</a></li><li><a href="./testing.html">Testing</a></li></ul>',14),s=[i];function o(c,l,h,d,g,u){return a(),t("div",null,s)}const y=e(n,[["render",o]]);export{m as __pageData,y as default};
